# Validate incoming brand requirements
import json

item = _input.item['json']
errors = []

# Required field validation
if not item.get('brandName') or item['brandName'] == 'Unknown Brand':
    errors.append('brandName is required')

if item.get('budgetUSD', 0) <= 0:
    errors.append('budgetUSD must be greater than 0')

if item.get('minEngagementRate', 0) < 0 or item.get('minEngagementRate', 0) > 100:
    errors.append('minEngagementRate must be between 0 and 100')

if item.get('minFollowers', 0) < 0:
    errors.append('minFollowers cannot be negative')

# Budget tier classification
budget = item.get('budgetUSD', 0)
if budget < 1000:
    budget_tier = 'nano'
elif budget < 10000:
    budget_tier = 'micro'
elif budget < 50000:
    budget_tier = 'mid'
else:
    budget_tier = 'macro'

return {
    'json': {
        **item,
        'isValid': len(errors) == 0,
        'validationErrors': errors,
        'budgetTier': budget_tier
    }
}

# Parse and merge influencer roster + engagement history into structured profiles
import json

items = _input.all()

# Expect two inputs: roster and engagement history
roster_raw = items[0]['json'].get('values', [])
engagement_raw = items[1]['json'].get('values', []) if len(items) > 1 else []

# Parse roster (header row first)
if not roster_raw or len(roster_raw) < 2:
    return [{'json': {'influencers': [], 'count': 0, 'error': 'Empty influencer roster'}}]

roster_headers = [h.strip().lower().replace(' ', '_') for h in roster_raw[0]]
influencers = []
for row in roster_raw[1:]:
    if not any(row):
        continue
    profile = {roster_headers[i]: row[i] if i < len(row) else '' for i in range(len(roster_headers))}
    profile['follower_count'] = int(profile.get('follower_count', 0) or 0)
    profile['engagement_rate'] = float(profile.get('engagement_rate', 0) or 0)
    profile['avg_cpe'] = float(profile.get('avg_cpe', 0) or 0)
    profile['conversion_rate'] = float(profile.get('conversion_rate', 0) or 0)
    profile['avg_reach'] = int(profile.get('avg_reach', 0) or 0)
    influencers.append(profile)

# Parse engagement history and attach to influencers
if engagement_raw and len(engagement_raw) > 1:
    eng_headers = [h.strip().lower().replace(' ', '_') for h in engagement_raw[0]]
    for row in engagement_raw[1:]:
        if not any(row):
            continue
        eng = {eng_headers[i]: row[i] if i < len(row) else '' for i in range(len(eng_headers))}
        handle = eng.get('handle', '')
        for inf in influencers:
            if inf.get('handle', '') == handle:
                inf['recent_campaigns'] = inf.get('recent_campaigns', []) + [eng]

return [{'json': {'influencers': influencers, 'count': len(influencers)}}]

parameters.text:
=You are an expert influencer marketing strategist. Analyze the following brand requirements and top influencer matches, then generate a professional matchmaking report.

Brand: {{ $json.brandName }}
Industry: {{ $json.industry }}
Campaign Goal: {{ $json.campaignGoal }}
Target Audience: Age {{ $json.targetAgeRange }}, Gender: {{ $json.targetGender }}, Locations: {{ $json.targetLocations }}
Budget: ${{ $json.budgetUSD }} USD
Preferred Platforms: {{ $json.preferredPlatforms }}

Top Matched Influencers (scored and ranked):
{{ JSON.stringify($json.scoredInfluencers?.slice(0, 10)) }}

Your tasks:
1. Write a concise executive summary (3-4 sentences) about the overall match quality.
2. For the top 5 influencers, write a 2-3 sentence rationale explaining WHY they are a strong fit for this brand.
3. Highlight any risks or caveats (audience authenticity, niche drift, budget fit).
4. Suggest one creative campaign concept that aligns with the brand goal.

Format your response as structured JSON with keys: executiveSummary, topMatches (array with handle, rationale, conversionProbability), risks, campaignConcept.

parameters.jsCode:
const item = $input.item.json;

// Parse AI response (may be wrapped in markdown)
let aiOutput = item.output || item.response || '{}';
try {
  // Strip markdown code fences if present
  aiOutput = aiOutput.replace(/```json|```/g, '').trim();
  aiOutput = JSON.parse(aiOutput);
} catch (e) {
  aiOutput = { rawResponse: item.output || '', parseError: true };
}

// Build final ranked shortlist (top 10)
const topInfluencers = (item.scoredInfluencers || []).slice(0, 10).map((inf, idx) => ({
  rank: idx + 1,
  handle: inf.handle || inf.name || 'Unknown',
  name: inf.name || inf.handle || 'Unknown',
  niche: inf.niche || 'General',
  platform: inf.platforms || 'Instagram',
  followerCount: inf.follower_count || 0,
  engagementRate: inf.engagement_rate || 0,
  conversionRate: inf.conversion_rate || 0,
  matchScore: inf.matchScore || 0,
  conversionProbability: inf.conversionProbability || 0,
  matchReasons: (inf.matchReasons || []).join('; '),
  estimatedCostPerPost: inf.avg_cpe || 0,
  topLocations: inf.top_locations || '',
  audienceAge: inf.primary_audience_age || '',
  audienceGender: inf.primary_audience_gender || ''
}));

return {
  json: {
    requestId: item.requestId,
    brandName: item.brandName,
    industry: item.industry,
    campaignGoal: item.campaignGoal,
    budgetUSD: item.budgetUSD,
    totalCandidatesEvaluated: item.totalCandidates || 0,
    totalMatched: topInfluencers.length,
    rankedShortlist: topInfluencers,
    executiveSummary: aiOutput.executiveSummary || '',
    aiTopMatches: aiOutput.topMatches || [],
    risks: aiOutput.risks || '',
    campaignConcept: aiOutput.campaignConcept || '',
    generatedAt: new Date().toISOString()
  }
};

